def check_padding(ciphertext_hex):
    """Returns VALID if padding is correct, INVALID otherwise."""
    ct = bytes.fromhex(ciphertext_hex)
    ct_int = bytes_to_long(ct)
    pt_int = pow(ct_int, D, N)
    pt = long_to_bytes(pt_int, 256)
    if len(pt) >= 11 and pt[0] == 0 and pt[1] == 2:
        i = 2
        while i < len(pt) and pt[i] != 0:
            i += 1
        if i < len(pt) and i >= 8:
            return "VALID"
    return "INVALID"
